// Input: Array A[0..k-1] containing first element from each of k sorted sequences
// Output: Complete winner tree stored in array Tree[0..2k-2]

BEGIN WinnerTreeConstruction(A, k)
    // Step 1: Copy leaves to tree array (indices k to 2k-1 represent leaves)
    FOR i FROM 0 TO k-1 DO
        Tree[k + i] ← A[i]
    END FOR

    // Fill dummy leaves with +∞ for non-power-of-2
    nextPower ← Smallest power of 2 ≥ k
    FOR i FROM k TO nextPower-1 DO
        Tree[k + i] ← +∞
    END FOR

    // Step 2: Build internal nodes bottom-up
    FOR i FROM nextPower-1 DOWNTO 1 DO
        Tree[i] ← min(Tree[2*i], Tree[2*i + 1])  // Store winner
    END FOR

    RETURN Tree
END

// Time Complexity: O(k) - exactly (nextPower-1) comparisons
// Space Complexity: O(k) for tree storage

// Input: Tree[1..n] where 1 is root, leaves at indices n/2+1 to n
//       leafIndex: index of leaf that received new element
//       newValue: next element from the same sequence
// Output: Updated winner tree with new winner at root

BEGIN WinnerTreeUpdate(Tree, leafIndex, newValue)
    Tree[leafIndex] ← newValue

    // Calculate parent index
    parent ← leafIndex / 2

    WHILE parent >= 1 DO
        leftChild ← 2 * parent
        rightChild ← 2 * parent + 1

        // Compare both children to find winner at parent
        IF Tree[leftChild] <= Tree[rightChild] THEN
            Tree[parent] ← Tree[leftChild]
        ELSE
            Tree[parent] ← Tree[rightChild]
        END IF

        parent ← parent / 2
    END WHILE

    RETURN Tree
END

// Time Complexity: O(log k) where k is number of leaves
// Each iteration moves one level up the tree
// Maximum ⌈log₂k⌉ iterations for complete binary tree

// Input: Tree[1..n] loser tree, leafIndex where element was replaced
//       newValue: new element at that leaf position
// Output: Updated loser tree

BEGIN LoserTreeUpdate(Tree, leafIndex, newValue)
    Tree[leafIndex] ← newValue

    // Start from leaf's parent
    parent ← leafIndex / 2
    winner ← newValue

    WHILE parent >= 1 DO
        // Compare with stored loser at parent
        storedLoser ← Tree[parent]

        // Winner always moves up (smaller value wins in min selection)
        IF winner < storedLoser THEN
            // Current winner is smaller than stored loser
            // Swap: winner goes up, storedLoser becomes new loser at parent
            Tree[parent] ← winner
            winner ← storedLoser
        ELSE
            // storedLoser remains the loser, winner is larger
            // No change to tree[parent], winner stays same for next level
        END IF

        parent ← parent / 2
    END WHILE

    RETURN Tree
END

// Time Complexity: O(log k)
// Advantage over winner tree: only ONE comparison per level
// Winner tree needs 2 comparisons per level (compare with sibling, then parent)
// Loser tree stores opponent, so only 1 comparison needed
